create table dirkspzm32.s_rcv_auftr (
    firma_nr            number(2, 0) not null enable,
    auf_id              number(*, 0) not null enable,
    vorgang             number(*, 5),
    satzart             varchar2(3 char),
    auftrag             number(*, 5),
    pos_nr              number(10, 0),
    upos_nr             number(10, 0),
    artikel             varchar2(30 char),
    adr_art             varchar2(1 char),
    adr_nr              varchar2(20 char),
    adr_liefer          varchar2(20 char),
    leitzahl            number(*, 5),
    charge              varchar2(60 char),
    seriennr            varchar2(20 char),
    strategie           varchar2(10 char),
    mhd                 date,
    li_nr               number(*, 5),
    li_pos_nr           number(10, 0),
    arbeitsplatz_id     varchar2(10 char),
    kom_info            varchar2(40 char),
    soll_mg             number(12, 3),
    ist_menge           number(12, 3),
    status              varchar2(1 char),
    wa_ziel             varchar2(6 char),
    gen_datum           date,
    lvs_info            varchar2(40 char),
    prioritaet          number(1, 0),
    best_nr_kunde       varchar2(30 char),
    fa_ag               number(*, 5),
    ziel                varchar2(30 char),
    anbruch             varchar2(1 char),
    liefer_datum        date,
    besteller           varchar2(10 char),
    lam_sel1            varchar2(30 char),
    lam_sel2            varchar2(30 char),
    lam_sel3            varchar2(30 char),
    lam_sel4            varchar2(30 char),
    lam_sel5            varchar2(30 char),
    lam_sel6            varchar2(30 char),
    lam_sel7            varchar2(30 char),
    lam_sel8            varchar2(30 char),
    lam_sel9            varchar2(30 char),
    lam_sel10           varchar2(30 char),
    tour                varchar2(20 char),
    ueber_unter_liefern varchar2(4 char)
);

alter table dirkspzm32.s_rcv_auftr
    add constraint pk_s_res_auftraege primary key ( firma_nr,
                                                    auf_id )
        using index enable;


